using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Preserve the old name so existing
            // 500K documents (and raw SQL that references c.Discriminator)
            // continue to work.
            entity.HasDiscriminatorInJsonProperty("Discriminator");

            // EF Core 9 changed the default id format from "EntityType|Key"
            // to just "Key". Preserve the old format so existing documents
            // with ids like "Product|123" remain readable.
            entity.HasIdProperty(nameof(Product.Id))
                  .HasIdJsonProperty("id");
            entity.Property(p => p.Id)
                  .HasValueGeneratorFactory<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGeneratorFactory>();

            // EF Core 9 throws for HasIndex on Cosmos (was silently ignored).
            // Removed: entity.HasIndex(p => p.Sku);
            // Cosmos indexes are managed via indexing policy on the container,
            // not through EF Core.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

