class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // as the JSON property name via HasDiscriminatorInJsonProperty().
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider removed synchronous I/O.
        // ToList() → ToListAsync(); the method must be async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

